  const [form, setForm] = useState({
    idUsuario: "",
    idQuarto: "",
    dtInicio: toInputDate(new Date()),
    dtFim: toInputDate(new Date(Date.now() + 24 * 3600 * 1000)),
    hospedeNome: "",
